"""SQLAlchemy ORM expressions -- no SQL string literals at all.

These are the legacy ``session.query(Model)`` API and the SQLAlchemy 2.0
``select(Model).where(...)`` API. The SQL is generated by the ORM from Python
expression objects; nothing in source is a hand-written SQL statement.
"""

from __future__ import annotations

from sqlalchemy import and_, func, select
from sqlalchemy.orm import Session


class User:
    id: int
    email: str
    active: bool
    role: str


def active_users_legacy(session: Session):
    return session.query(User).filter(User.active == True).all()


def admin_users_2x(session: Session):
    stmt = select(User).where(User.role == "admin")
    return session.execute(stmt).scalars().all()


def user_by_email(session: Session, email: str):
    stmt = select(User).where(User.email == email)
    return session.execute(stmt).scalar_one_or_none()


def user_count_per_role(session: Session):
    stmt = select(User.role, func.count(User.id)).group_by(User.role)
    return session.execute(stmt).all()


def active_admins(session: Session):
    return (
        session.query(User)
        .filter(and_(User.active == True, User.role == "admin"))
        .order_by(User.email)
        .all()
    )


def delete_inactive(session: Session):
    session.query(User).filter(User.active == False).delete()
    session.commit()
